        $r.NewVersion | Should -Be '1.2.0'
        (Get-Content -Path $script:vf -Raw).Trim() | Should -Be '1.2.0'
        Test-Path $script:cf | Should -BeTrue
        (Get-Content -Path $script:cf -Raw) | Should -Match '## 1\.2\.0'
    }
