            @{ Name='fix';      Fixture='fixtures/commits-fix.txt';      Start='1.1.0'; Expected='1.1.1'; Bump='patch' }
            @{ Name='breaking'; Fixture='fixtures/commits-breaking.txt'; Start='1.1.0'; Expected='2.0.0'; Bump='major' }
